function escapeHtml(s) {
  return String(s ?? "").replace(
    /[&<>"']/g,
    (m) =>
      ({
        "&": "&amp;",
        "<": "&lt;",
        ">": "&gt;",
        '"': "&quot;",
        "'": "&#039;",
      })[m],
  );
}
function pretty(v) {
  if (v === null || v === undefined || v === "")
    return '<span class="empty">Tidak ada</span>';
  if (typeof v === "string") return "<pre>" + escapeHtml(v) + "</pre>";
  return "<pre>" + escapeHtml(JSON.stringify(v, null, 2)) + "</pre>";
}
function normalizeUrl(u) {
  return String(u || "").replaceAll("{{url}}", "{base_url}");
}
function rows(list, cols) {
  if (!list || !list.length) return '<p class="empty">Tidak ada</p>';
  return (
    "<table><thead><tr>" +
    cols.map((c) => "<th>" + c + "</th>").join("") +
    "</tr></thead><tbody>" +
    list
      .map(
        (r) =>
          "<tr>" +
          cols
            .map(
              (c, i) =>
                "<td>" +
                escapeHtml(Array.isArray(r) ? r[i] : (r[c] ?? "")) +
                "</td>",
            )
            .join("") +
          "</tr>",
      )
      .join("") +
    "</tbody></table>"
  );
}
function slug(s) {
  return (
    String(s || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/(^-|-$)/g, "") || "other"
  );
}
function flatten() {
  return apiData.flatMap((c) =>
    c.endpoints.map((e, i) => ({
      ...e,
      collection: c.name,
      idx: i,
      groupId: slug(c.name + " " + (e.folder || "Other")),
    })),
  );
}
const endpoints = flatten();
const allCollections = apiData.map((c) => ({
  name: c.name,
  count: c.endpoints.length,
}));
function jsString(s) {
  return JSON.stringify(String(s ?? ""));
}
const methodColor = (m) => escapeHtml(m || "GET");
function renderStats(items) {
  const counts = {};
  items.forEach((e) => (counts[e.method] = (counts[e.method] || 0) + 1));
  document.getElementById("stats").innerHTML =
    `<div class="stat"><b>${items.length}</b><span>Total Endpoint</span></div><div class="stat"><b>${new Set(items.map((e) => e.collection)).size}</b><span>Collection</span></div><div class="stat"><b>${new Set(items.map((e) => e.collection + " / " + e.folder)).size}</b><span>Folder</span></div>` +
    Object.entries(counts)
      .map(([m, n]) => `<div class="stat"><b>${n}</b><span>${m}</span></div>`)
      .join("");
}
function endpointHtml(e) {
  let params = [
    ...(e.path_params || []).map((p) => [p, "path", ""]),
    ...(e.query_params || []).map((q) =>
      Array.isArray(q) ? [q[0], "query", q[1] || ""] : [q, "query", ""],
    ),
  ];
  let resp = e.response || {};
  let url = normalizeUrl(e.url);
  return `<div class="endpoint" data-method="${escapeHtml(e.method)}" data-folder="${escapeHtml(e.folder || "Other")}" data-collection="${escapeHtml(e.collection)}"><button class="summary" onclick="this.parentElement.classList.toggle('open')"><span class="method ${methodColor(e.method)}">${escapeHtml(e.method)}</span><span><div class="epname">${escapeHtml(e.name)} <span class="badge">${escapeHtml(e.collection)}</span></div><div class="path">${escapeHtml(url)}</div></span><span class="auth">${escapeHtml(e.auth || "Inherited")}</span></button><div class="details"><div class="toolbar"><button class="copy" onclick='copyText(${jsString(url)})'>Copy URL</button><button class="copy" onclick='copyText(${jsString((e.method || "GET") + " " + url)})'>Copy Method + URL</button></div><div class="grid"><div class="card"><p class="doc-title">Request</p><p class="doc-item"><b>Auth:</b> ${escapeHtml(e.auth || "Inherited")}</p><p class="doc-item"><b>Endpoint:</b> </br> <code class="mb-2">${escapeHtml(url)}</code></p><p class="doc-title">Parameters</p>${rows(params, ["Name", "In", "Value"])}<p class="doc-title">Headers</p>${rows(e.headers || [], ["key", "value"])}<p class="doc-title">Body</p>${pretty(e.request_body)}</div><div class="card"><p class="doc-title">Response ${resp.code ? escapeHtml(resp.code) : ""} ${resp.status ? "- " + escapeHtml(resp.status) : ""}</p>${pretty(resp.body || resp)} </div></div></div></div>`;
}
function currentFilters() {
  return {
    q: document.getElementById("search").value.toLowerCase(),
    mf: document.getElementById("methodFilter").value,
    cf: document.getElementById("collectionFilter").value,
  };
}
function filteredItems() {
  const { q, mf, cf } = currentFilters();
  return endpoints.filter(
    (e) =>
      (!mf || e.method === mf) &&
      (!cf || e.collection === cf) &&
      JSON.stringify(e).toLowerCase().includes(q),
  );
}
function render() {
  let items = filteredItems();
  renderStats(items);
  let groups = {};
  items.forEach((e) => {
    let key = e.collection + " / " + (e.folder || "Other");
    (groups[key] ||= []).push(e);
  });
  document.getElementById("docs").innerHTML =
    Object.entries(groups)
      .map(
        ([g, arr]) =>
          `<h2 class="group-title" id="${slug(g)}">${escapeHtml(g)} <span class="muted">(${arr.length})</span></h2>` +
          arr.map(endpointHtml).join(""),
      )
      .join("") ||
    '<div class="hero"><p>Tidak ada endpoint yang cocok.</p></div>';
  renderFolders(items);
  updateActiveMenus();
}
function renderFolders(items) {
  let map = new Map();
  items.forEach((e) => {
    let name = e.folder || "Other",
      key = e.collection + " / " + name;
    map.set(key, (map.get(key) || 0) + 1);
  });
  document.getElementById("folderNav").innerHTML = [...map.entries()]
    .sort()
    .map(
      ([key, count]) =>
        `<a class="navlink" data-folder-link="${escapeHtml(key)}" href="#${slug(key)}" onclick="setActiveFolder(${jsString(key)})">${escapeHtml(key)} <span>${count}</span></a>`,
    )
    .join("");
}
function setCollectionFilter(name) {
  document.getElementById("collectionFilter").value = name;
  activeFolder = "";
  render();
  window.scrollTo({ top: 0, behavior: "smooth" });
}
let activeFolder = "";
function setActiveFolder(key) {
  activeFolder = key;
  setTimeout(updateActiveMenus, 20);
}
function updateActiveMenus() {
  const cf = document.getElementById("collectionFilter").value;
  document
    .querySelectorAll("#collectionNav a")
    .forEach((a) => a.classList.toggle("active", a.dataset.collection === cf));
  document
    .querySelectorAll("#folderNav a")
    .forEach((a) =>
      a.classList.toggle("active", a.dataset.folderLink === activeFolder),
    );
}
function renderCollectionNav() {
  let total = endpoints.length;
  let links = [
    `<a href="#" data-collection="" onclick="setCollectionFilter('');return false">All Collections <span>${total}</span></a>`,
  ];
  allCollections.forEach((c) =>
    links.push(
      `<a href="#" data-collection="${escapeHtml(c.name)}" onclick='setCollectionFilter(${jsString(c.name)});return false'>${escapeHtml(c.name)} <span>${c.count}</span></a>`,
    ),
  );
  document.getElementById("collectionNav").innerHTML = links.join("");
  updateActiveMenus();
}
function copyText(t) {
  navigator.clipboard && navigator.clipboard.writeText(t);
}
const cf = document.getElementById("collectionFilter");
allCollections.forEach((c) => {
  let o = document.createElement("option");
  o.value = c.name;
  o.textContent = c.name;
  cf.appendChild(o);
});
document.getElementById("search").addEventListener("input", render);
document.getElementById("methodFilter").addEventListener("change", render);
cf.addEventListener("change", () => {
  activeFolder = "";
  render();
});
renderCollectionNav();
render();
